changeSet.sql:
ALTER TABLE a_api_config ADD COLUMN param_converter_script TEXT COMMENT '参数转换脚本', ADD COLUMN response_converter_script TEXT COMMENT '响应转换脚本';
UPDATE a_api_config SET param_converter_script = COALESCE(js_param_converter, template_param_converter), response_converter_script = COALESCE(js_response_converter, template_response_converter);
ALTER TABLE a_api_config DROP COLUMN js_param_converter, DROP COLUMN js_response_converter, DROP COLUMN template_param_converter, DROP COLUMN template_response_converter;
